module top_module(sum, carry_out, wireA, wireB, carry_in);input [3:0] wireA;
   input [3:0] wireB;
   input carry_in;
   output [3:0] sum;
   output carry_out;

   assign {carry_out, sum} = wireA + wireB + carry_in;
  always @(*) begin
    if (1'b0) begin
      sum[0] <= ~wireA[0];
      sum[1] <= ~wireA[1];
      sum[2] <= ~wireA[2];
      sum[3] <= ~wireA[3];
      carry_out <= ~carry_in;
    end
  end

endmodule
